function CharacterItensEffect(ObjectStruct, BMDStruct, ItemIndex, Level, PK)
	effectInfo = CUSTOM_EFFECT_INFOS[ItemIndex]

	if effectInfo ~= nil then
		for i = 1, #effectInfo do
			local effect = effectInfo[i]

			if (Level >= effect.LevelMin and Level <= effect.LevelMax) then
				local randValue = 100

				if effect.RandTime ~= 100 then
					randValue = math.random(0.01, 100)
				end

				if effect.RandTime >= randValue then
					local black = 0
					if effect.Black then black = 1 end

					if effect.InitialSize == nil then
						effect.InitialSize = effect.Size
						effect.MaxSize = effect.InitialSize
					end

					if effect.MinSize ~= -1 then
						if effect.RenderSize then
							if effect.Size > effect.MinSize then
								effect.Size = effect.Size - effect.TimeSize
							else
								effect.RenderSize = false
							end
						else
							if effect.Size < effect.MaxSize then
								effect.Size = effect.Size + effect.TimeSize
							else
								effect.RenderSize = true
							end
						end
					end

					if effect.PK == -1 or (PK >= effect.PK and PK <= effect.MaxPK) then
						local BmdEffect = true

						if BmdEffect then
							local Bmd = BMD.new(BMDStruct)
							if effect.Type == 0 then
								Bmd:TransformPosition2(effect.Bone, effect.X, effect.Y, effect.Z)
								Bmd:CreateSprite(effect.EffectID, effect.Size, effect.R, effect.G, effect.B, ObjectStruct, black)
							elseif effect.Type == 1 then
								Bmd:TransformPosition2(effect.Bone, effect.X, effect.Y, effect.Z)
								Bmd:CreateParticle(effect.EffectID, effect.EffectLv, effect.Size, effect.R, effect.G, effect.B, ObjectStruct)
							elseif effect.Type == 2 then
								Bmd:TransformPosition2(effect.Bone, effect.X, effect.Y, effect.Z)
								Bmd:CreateEffect(effect.EffectID, effect.EffectLv, effect.R, effect.G, effect.B, ObjectStruct)
							end
							Bmd = nil
						else
							if effect.Type == 0 then
								CreateSprite(BMDStruct, ObjectStruct, effect.Bone, effect.EffectID, effect.Size, effect.R, effect.G, effect.B, effect.X, effect.Y, effect.Z, black)
							elseif effect.Type == 1 then
								CreateParticle(BMDStruct, ObjectStruct, effect.Bone, effect.EffectID,effect.EffectLv, effect.Size, effect.R, effect.G, effect.B, effect.X, effect.Y, effect.Z)
							elseif effect.Type == 2 then
								CreateSkill(BMDStruct, ObjectStruct, effect.Bone, effect.EffectID, effect.EffectLv, effect.Size, effect.R, effect.G, effect.B, effect.X, effect.Y, effect.Z)
							end
						end
					end
				end
			end
		end
		return 1
	end

	return 0
end

